export function getWordBank(): VocabWord[] {
  return WORD_BANK
}

export function getWordsForDay(day: number, wordsPerDay: number = 50): VocabWord[] {
  const start = (day - 1) * wordsPerDay
  return WORD_BANK.slice(start, start + wordsPerDay)
}

export function searchWords(keyword: string): VocabWord[] {
  const kw = keyword.toLowerCase()
  return WORD_BANK.filter(w => 
    w.word.toLowerCase().includes(kw) || 
    w.meaning.includes(keyword)
  ).slice(0, 100)
}

export function getWord(word: string): VocabWord | undefined {
  return WORD_BANK.find(w => w.word.toLowerCase() === word.toLowerCase())
}

export const TOTAL_WORDS = WORD_BANK.length
